import{c as t,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse(`{"title":"Ben's Bites — 2026-04-02","description":"","frontmatter":{"title":"Ben's Bites — 2026-04-02","date":"2026-04-02T00:00:00.000Z","source":"Ben's Bites","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-02-bens-bites.md","filePath":"research/ai-news/2026-04/2026-04-02-bens-bites.md","lastUpdated":1779796674000}`),s={name:"research/ai-news/2026-04/2026-04-02-bens-bites.md"};function n(i,e,l,u,p,h){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="🍔-ben-s-bites-—-2026-04-02" tabindex="-1">🍔 Ben&#39;s Bites — 2026-04-02 <a class="header-anchor" href="#🍔-ben-s-bites-—-2026-04-02" aria-label="Permalink to &quot;🍔 Ben&#39;s Bites — 2026-04-02&quot;">​</a></h1><blockquote><p>Ben Tossell 的 AI 日報，工具圈消息源 來源：<a href="https://www.bensbites.com/feed" target="_blank" rel="noreferrer">Ben&#39;s Bites</a></p></blockquote><hr><h2 id="inside-the-leaked-claude-code-files" tabindex="-1"><a href="https://www.bensbites.com/p/inside-the-leaked-claude-code-files" target="_blank" rel="noreferrer">Inside the leaked Claude Code files</a> <a class="header-anchor" href="#inside-the-leaked-claude-code-files" aria-label="Permalink to &quot;[Inside the leaked Claude Code files](https://www.bensbites.com/p/inside-the-leaked-claude-code-files)&quot;">​</a></h2><p><em>🍔 Ben&#39;s Bites | 2026-04-02</em></p><p>Anthropic accidentally leaked the entire source code of Claude Code, due to a human error in one of their processes. Revealing the tool’s full architecture, internal prompts, agent workflows, tool usage, permission systems, and unreleased/hidden features. Boris, the lead for Claude Code, confirmed that this was a developer error, not any bug in Bun or a hack.</p><p>Re unreleased/hidden features (because I know you wanna know); “Proactive” mode (AI works autonomously without prompts), frustration/anger detection via keyword patterns is marked ‘negative’ in their analytics, a <a href="https://x.com/alistaiir/status/2039429708014829764" target="_blank" rel="noreferrer">Tamagotchi-like “/buddy”</a> companion, background daemons (like OpenClaw uses), undercover commit-hiding mode, and more feature flags/roadmap items.</p><p>The community ran rampant cloning the codebase on GitHub (which Anthropic since sent DMCA notices to get them taken down). But some <a href="https://github.com/ultraworkers/claw-code" target="_blank" rel="noreferrer">developers ported the code</a> to other languages (Python and then Rust) - which has copyright greyness and if Anthropic push to get them removed, may bring up questions on their own copyright issues.</p><p>Since it was April Fools yesterday, many launches are indistinguishable from real ones - I think it’s getting harder to spot in the AI age too.</p><p>But some folks use it as an opportunity to launch things, like <a href="https://x.com/shl/status/2039401205311398027" target="_blank" rel="noreferrer">Gumroad replacing their CEO with an AI Agent</a>. Sahil (the founder) is a friend and previously invested in my last company. He’s super smart and I don’t think this is a prank at all. He’s the kind of person to try wacky, out-there things to see if they stick.</p><p>Some companies actually do April Fools well, like ElevenLabs. Last year, they made dogs talk, and this year, they are partnering with the 3000-year-old <a href="https://x.com/ElevenLabs/status/2039371517104910407" target="_blank" rel="noreferrer">ElvenLabs</a>.</p><p>Ben’s Bites is brought to you by <a href="https://www.llamaindex.ai/bens-bites?utm_source=sponsor&amp;utm_medium=bensbites&amp;utm_campaign=bb-newsletter-2026-04-02" target="_blank" rel="noreferrer">LlamaIndex</a></p><p>Your agent can write code but it can’t accurately read PDFs. Classic.</p><p><a href="https://www.llamaindex.ai/bens-bites?utm_source=sponsor&amp;utm_medium=bensbites&amp;utm_campaign=bb-newsletter-2026-04-02" target="_blank" rel="noreferrer">LlamaParse</a> 🦙 reads docs with 99%+ accuracy on complex PDFs–like SEC reports, invoices, or research papers. Give your agents the context they need.</p><p>Sign up today to get 20,000 free credits with coupon: <a href="https://www.llamaindex.ai/bens-bites?utm_source=sponsor&amp;utm_medium=bensbites&amp;utm_campaign=bb-newsletter-2026-04-02" target="_blank" rel="noreferrer">BENSBITES20</a> (ends 4/10)</p><p>I invested in LlamaIndex when scouting for a16z a few years ago</p><p>Headlines</p><p><a href="https://x.com/bcherny/status/2039421575422980329" target="_blank" rel="noreferrer">Claude Code now renders a full UI in your terminal</a> to solve the flickering. It shows “N new messages” when you scroll up, gives you full mouse support, and constant memory use. It’s experimental for now; upgrade to the latest version and run using “CLAUDE_CODE_NO_FLICKER=1 claude”.</p><p><a href="https://openai.com/index/accelerating-the-next-phase-ai/" target="_blank" rel="noreferrer">OpenAI closed its $122B raise at a $852B post-money valuation</a>. It’s making about $2B a month in revenue, 40% of which comes from the enterprise. The blog post outlines a lot of their plans that were previously just rumours/leaks from various newsrooms.</p><p><a href="https://www.salesforce.com/slack/slackbot/agent-orchestration/" target="_blank" rel="noreferrer">Slack is turning Slackbot into a desktop companion</a>. Select anything on your screen, pass it to Slackbot, and it can answer based on the context from your Slack workspace. It has 30+ new capabilities, including meeting transcription, reusable AI skills, MCP client and a native CRM.</p><p><a href="https://softr.io/build-with/ben-s-bites?utm_source=ben%27s_bites&amp;utm_medium=influencer&amp;utm_campaign=ai_co-builder&amp;utm_content=bensbites_march_launch_post" target="_blank" rel="noreferrer">Softr AI</a> builds the tool your business needs, not a prototype. It wires the whole thing: database, logic, logins, permissions, &amp; security (even hosting) with a visual editor to fine-tune. Think client portals, internal tools, CRMs, and more. No code required. 👉 <a href="https://softr.io/build-with/ben-s-bites?utm_source=ben%27s_bites&amp;utm_medium=influencer&amp;utm_campaign=ai_co-builder&amp;utm_content=bensbites_march_launch_post" target="_blank" rel="noreferrer">Start today</a> with 200 free AI credits.*</p><p>My feed</p><p><a href="https://attio.com/?utm_source=bens_bites&amp;utm_medium=newsletter_sponsorship&amp;utm_campaign=bens_bites-Y26" target="_blank" rel="noreferrer">Attio</a> - The AI CRM that does the work for you.*</p><p><a href="https://rivet.dev/agent-os/" target="_blank" rel="noreferrer">AgentOS by Rivet.dev</a> - open-source operating system for agents. ~6 ms coldstarts, 32x cheaper than sandboxes.</p><p>Mario, the founder of Pi, asked around for something like Google Docs, but for markdown. He then vibed <a href="https://github.com/badlogic/jot" target="_blank" rel="noreferrer">Jot</a> in an hour.</p><p>Your agents can now access <a href="https://supabase.com/blog/supabase-docs-over-ssh" target="_blank" rel="noreferrer">Supabase’s full documentation</a> as a virtual filesystem. I think Mintlify could offer this to their customers, similar to how they added the “Copy as Markdown” button to the docs hosted via Mintlify.</p><p><a href="https://simonwillison.net/2026/Mar/27/vibe-coding-swiftui/" target="_blank" rel="noreferrer">Vibe coding SwiftUI apps</a> is a lot of fun.</p><p>Simple Mac app to <a href="https://x.com/gabrielvaldivia/status/2039459190310092855" target="_blank" rel="noreferrer">run skills on a schedule</a> via Claude Code.</p><p>Exa’s new product, <a href="https://x.com/ExaAILabs/status/2039389253524983857" target="_blank" rel="noreferrer">Monitors</a>, returns fresh results from the web for your query on schedule. Feels relevant for building agents.</p><p>Yutori’s Scouts do something similar for humans. They also launched <a href="https://x.com/abhshkdz/status/2039375055445250202" target="_blank" rel="noreferrer">Yutori’s desktop app</a> for local-only access to logged-in websites when creating these “what’s new for your query” reports.</p><p><a href="https://benhylak.substack.com/p/the-case-against-personalized-software" target="_blank" rel="noreferrer">The case against personal software</a>.</p><p>Cloudflare launched a <a href="https://blog.cloudflare.com/emdash-wordpress/" target="_blank" rel="noreferrer">successor to WordPress</a> with a focus on plugin security.</p><p>How Zapier measures the <a href="https://zapier.com/blog/raising-ai-fluency-bar-in-hiring/" target="_blank" rel="noreferrer">AI fluency of every hire</a> across all departments.</p><p>Block wants to <a href="https://block.xyz/inside/from-hierarchy-to-intelligence" target="_blank" rel="noreferrer">move away from traditional human hierarchies</a> and transition to one guided by an intelligence layer.</p><p>Microsoft is working towards adding <a href="https://x.com/OmarShahine/status/2039023022699655297" target="_blank" rel="noreferrer">OpenClaw-style personal agents</a> to M365.</p><p>Afters</p><p>@scmallaby&#39;s brilliant new book about Demis Hassabis and DeepMind.\\n\\nThis is the inside story of Project Mario. How DeepMind&#39;s co-founders spent 4 years trying every mechanism they could think of to put guardrails around AGI, only to &quot;,&quot;username&quot;:&quot;colossusmag&quot;,&quot;name&quot;:&quot;Colossus&quot;,&quot;profile_image_url&quot;:&quot;<a href="https://pbs.substack.com/profile_images/2011815065876643842/y70Ap2E__normal.jpg%22,%22date%22:%222026-03-31T10:00:01.000Z%22,%22photos%22:%5B%7B%22img_url%22:%22https://pbs.substack.com/media/HEusXUcbcAAiME4.jpg%22,%22link_url%22:%22https://t.co/acSas1dRzE%22%7D%5D,%22quoted_tweet%22:%7B%7D,%22reply_count%22:22,%22retweet_count%22:159,%22like_count%22:1236,%22impression_count%22:857398,%22expanded_url%22:null,%22video_url%22:null,%22belowTheFold%22:true%7D%22" target="_blank" rel="noreferrer">https://pbs.substack.com/profile_images/2011815065876643842/y70Ap2E__normal.jpg&quot;,&quot;date&quot;:&quot;2026-03-31T10:00:01.000Z&quot;,&quot;photos&quot;:[{&quot;img_url&quot;:&quot;https://pbs.substack.com/media/HEusXUcbcAAiME4.jpg&quot;,&quot;link_url&quot;:&quot;https://t.co/acSas1dRzE&quot;}],&quot;quoted_tweet&quot;:{},&quot;reply_count&quot;:22,&quot;retweet_count&quot;:159,&quot;like_count&quot;:1236,&quot;impression_count&quot;:857398,&quot;expanded_url&quot;:null,&quot;video_url&quot;:null,&quot;belowTheFold&quot;:true}&quot;</a> data-component-name=&quot;Twitter2ToDOM&quot;&gt;</p><p>Find me on <a href="https://x.com/bentossell/" target="_blank" rel="noreferrer">X</a>, <a href="https://www.linkedin.com/in/ben-tossell-70453537/" target="_blank" rel="noreferrer">Linkedin</a>, or <a href="https://www.youtube.com/@bentossell694" target="_blank" rel="noreferrer">YouTube</a></p><p>Read <a href="https://bensbites.substack.com/about" target="_blank" rel="noreferrer">about me</a> and Ben’s Bites</p><p>📷 thumbnail by <a href="https://www.x.com/keshavatearth" target="_blank" rel="noreferrer">@keshavatearth</a></p><ul><li>sponsors who make this newsletter possible 😃</li></ul><p>Wanna partner with us for the next quarter?</p><p>Email us at <a href="mailto:shanice@bensbites.com" target="_blank" rel="noreferrer">shanice@bensbites.com</a> or <a href="mailto:k@bensbites.com" target="_blank" rel="noreferrer">k@bensbites.com</a></p><hr>',44)])])}const m=t(s,[["render",n]]);export{d as __pageData,m as default};
